import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"Master's Programs","description":"Introduction to overseas master's programs and tips for applying to graduate programs abroad from a SCUT undergraduate background.","frontmatter":{"lang":"en-US","title":"Master's Programs","description":"Introduction to overseas master's programs and tips for applying to graduate programs abroad from a SCUT undergraduate background.","llm_translated":true},"headers":[],"relativePath":"en/beyond/abroad/master.md","filePath":"en/beyond/abroad/master.md","lastUpdated":1784829332000}`),a={name:`en/beyond/abroad/master.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/beyond/abroad/master.md for this page in Markdown format</div><h1 id="overseas-master-s-programs" tabindex="-1">Overseas Master&#39;s Programs <a class="header-anchor" href="#overseas-master-s-programs" aria-label="Permalink to “Overseas Master&#39;s Programs”">​</a></h1><p>Introduction to overseas master&#39;s programs and tips for applying to graduate programs abroad from a SCUT undergraduate background.</p><h2 id="hong-kong-study-programs" tabindex="-1">Hong Kong Study Programs <a class="header-anchor" href="#hong-kong-study-programs" aria-label="Permalink to “Hong Kong Study Programs”">​</a></h2><p>Below is a summary of the key differences between <strong>MSc, MPhil, and PhD</strong> in the Hong Kong higher education system, covering <strong>duration, tuition, academic pathways, academic focus, and career orientation</strong>.</p><hr><h3 id="core-comparison-table" tabindex="-1">Core Comparison Table <a class="header-anchor" href="#core-comparison-table" aria-label="Permalink to “Core Comparison Table”">​</a></h3><table tabindex="0"><thead><tr><th><strong>Program</strong></th><th><strong>MSc (Taught Master&#39;s)</strong></th><th><strong>MPhil (Research Master&#39;s)</strong></th><th><strong>PhD (Research Doctorate)</strong></th></tr></thead><tbody><tr><td><strong>Duration</strong></td><td>1 year (full-time)</td><td>2 years (full-time)</td><td>4-5 years (full-time)</td></tr><tr><td><strong>Tuition (annual)</strong></td><td><strong>12-24万 HKD</strong> (25-35万 RMB) (self-funded)</td><td><strong>4.2万 HKD</strong> (subsidized)</td><td><strong>4.2万 HKD</strong> (subsidized)</td></tr><tr><td><strong>Scholarship</strong></td><td>Limited merit-based scholarships</td><td>Yes <strong>HKPFS/Professor funding</strong> (~18万 HKD/year)</td><td>Yes <strong>HKPFS/full scholarship</strong> (~25万 HKD/year)</td></tr><tr><td><strong>Academic Format</strong></td><td>Courses + exams/thesis</td><td>Research-focused + few courses</td><td><strong>Independent research + academic thesis</strong></td></tr><tr><td><strong>Career Path</strong></td><td>Employment</td><td>Stepping stone to PhD</td><td>Academia/research/high-end industry R&amp;D</td></tr><tr><td><strong>Graduation Requirements</strong></td><td>Complete credits + pass thesis</td><td>Publish paper + thesis defense</td><td><strong>International journal papers + PhD thesis defense</strong></td></tr><tr><td><strong>Application Difficulty</strong></td><td>Moderate (GPA + language scores)</td><td>High (research proposal + supervisor networking)</td><td>Very high (top research output + matching supervisor)</td></tr></tbody></table><hr><h3 id="academic-pathways-and-progression" tabindex="-1">Academic Pathways and Progression <a class="header-anchor" href="#academic-pathways-and-progression" aria-label="Permalink to “Academic Pathways and Progression”">​</a></h3><h4 id="msc-to-phd" tabindex="-1">MSc to PhD? <a class="header-anchor" href="#msc-to-phd" aria-label="Permalink to “MSc to PhD?”">​</a></h4><ul><li><strong>Extremely difficult</strong>: MSc lacks systematic research training; requires additional research experience (e.g., published papers) for PhD applications.</li></ul><h4 id="mphil-to-phd" tabindex="-1">MPhil to PhD <a class="header-anchor" href="#mphil-to-phd" aria-label="Permalink to “MPhil to PhD”">​</a></h4><ul><li>After the first year, pass the <strong>transfer assessment</strong> to directly enter the PhD phase (total duration: 2+2=4 years).</li></ul><h4 id="direct-entry-phd-from-undergraduate" tabindex="-1">Direct-entry PhD from Undergraduate <a class="header-anchor" href="#direct-entry-phd-from-undergraduate" aria-label="Permalink to “Direct-entry PhD from Undergraduate”">​</a></h4><ul><li><strong>Requirements</strong>: Top 985 university (GPA &gt;= 3.7) + research papers (first author) + strong recommendation letters. <strong>(Strong recommendation ≈ research papers &gt;&gt; GPA)</strong></li><li><strong>Advantage</strong>: Lowest total cost (scholarship covers the entire period).</li></ul><blockquote><p>⚠️ <strong>Heads-up</strong>: Undergraduates without research experience applying for MPhil/PhD face significant difficulty. It&#39;s strongly recommended to choose an MSc as a buffer!</p></blockquote>`,17)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};